const fs = require('fs');
const path = require('path');

/**
 * Auto-generated fix script for import errors
 * Generated by find-all-import-errors.js
 */

const fixes = [];

let fixedCount = 0;

for (const fix of fixes) {
  try {
    let content = fs.readFileSync(fix.file, 'utf8');
    const lines = content.split('\n');
    
    if (lines[fix.line - 1]) {
      const line = lines[fix.line - 1];
      const oldPath = fix.old;
      const newPath = fix.new;
      
      // Replace require statements
      const newLine = line
        .replace(new RegExp("require\\(['\"]" + oldPath.replace(/[.*+?^${}()|[\\]\\\\]/g, '\\\\$&') + "['\"]\\)", 'g'), "require('" + newPath + "')")
        .replace(new RegExp('require\\(["\']' + oldPath.replace(/[.*+?^${}()|[\\]\\\\]/g, '\\\\$&') + '["\']\\)', 'g'), 'require("' + newPath + '")');
      
      if (newLine !== line) {
        lines[fix.line - 1] = newLine;
        content = lines.join('\n');
        fs.writeFileSync(fix.file, content, 'utf8');
        console.log('✅ Fixed: ' + path.relative(__dirname, fix.file) + ':' + fix.line);
        fixedCount++;
      }
    }
  } catch (error) {
    console.error('❌ Error fixing ' + fix.file + ':', error.message);
  }
}

console.log('\n✅ Fixed ' + fixedCount + ' import(s)');
